SELECT * FROM "{{JSutils.currentSchema()}}".hotimun005
WHERE imun005_deleted <> true and imun005_desc ILIKE '%{{TableImuvia.searchText}}%'
ORDER BY
{{
  ({
    imun005_desc: 'imun005_desc',
    imun005_id: 'imun005_id'
  }[TableImuvia.sortOrder.column]) || 'imun005_desc'
}}
{{ TableImuvia.sortOrder.order === 'DESC' ? 'DESC' : 'ASC' }}
LIMIT {{TableImuvia.pageSize}}
OFFSET {{(TableImuvia.pageNo - 1) * TableImuvia.pageSize}};
